class SafeCounter {
    private int count = 0;
    public synchronized void increment() { count++; }
    public synchronized int getCount()   { return count; }
}

class UnsafeCounter { int c = 0; void inc() { c++; } }
class SafeCounter  { int c = 0; synchronized void inc() { c++; } }
public class App {
    static void runTest(Runnable inc, int[] result) throws InterruptedException {
        Thread[] threads = new Thread[5];
        for (int i=0; i<5; i++) threads[i] = new Thread(() -> { for (int j=0;j<200;j++) inc.run(); });
        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
    }
    public static void main(String[] args) throws InterruptedException {
        UnsafeCounter unsafe = new UnsafeCounter();
        runTest(unsafe::inc, null);
        System.out.println("Unsafe: " + unsafe.c);
        SafeCounter safe = new SafeCounter();
        runTest(safe::inc, null);
        System.out.println("Safe: " + safe.c);
    }
}

