class BankAccount {
    private final Object lock = new Object();
    private double balance;
    BankAccount(double init) { balance = init; }

    void deposit(double amount) {
        // pre-processing — can run concurrently
        synchronized (lock) {
            balance += amount;  // critical section only
        }
    }
    void withdraw(double amount) {
        synchronized (lock) { balance -= amount; }
    }
    double getBalance() {
        synchronized (lock) { return balance; }
    }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        BankAccount acct = new BankAccount(1000.0);
        Thread[] ts = new Thread[10];
        for (int i=0; i<5; i++) { ts[i]   = new Thread(() -> acct.deposit(100.0)); }
        for (int i=0; i<5; i++) { ts[i+5] = new Thread(() -> acct.withdraw(100.0)); }
        for (Thread t : ts) t.start();
        for (Thread t : ts) t.join();
        System.out.printf("Final: ₹%.2f%n", acct.getBalance());
    }
}

class ThreadSafeCounter {
    private int count = 0;
    public synchronized void increment() { count++; }
    public synchronized void decrement() { count--; }
    public synchronized void reset()     { count = 0; }
    public synchronized int getCount()   { return count; }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        ThreadSafeCounter ctr = new ThreadSafeCounter();
        Thread[] ts = new Thread[20];
        for (int i=0; i<10; i++)  ts[i]    = new Thread(() -> { for(int j=0;j<50;j++) ctr.increment(); });
        for (int i=0; i<10; i++)  ts[i+10] = new Thread(() -> { for(int j=0;j<30;j++) ctr.decrement(); });
        for (Thread t : ts) t.start();
        for (Thread t : ts) t.join();
        System.out.println("Final count: " + ctr.getCount());
    }
}

public class App {
    static volatile boolean stop = false;
    static volatile int volCount = 0;
    static int syncCount = 0;
    static final Object lock = new Object();

    public static void main(String[] args) throws InterruptedException {
        // 1. Volatile flag — works correctly
        Thread worker = new Thread(() -> {
