class Printer {
    synchronized void print(String msg) {
        System.out.print(msg + " ");
    }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        Printer p = new Printer();
        Thread t1 = new Thread(() -> { p.print("A"); p.print("B"); });
        Thread t2 = new Thread(() -> { p.print("X"); p.print("Y"); });
        t1.start(); t2.start();
        t1.join(); t2.join();
        System.out.println();
    }
}
```

exercises.expected_solution:
public class App {
    static final Object lock1 = new Object();
    static final Object lock2 = new Object();

    public static void main(String[] args) throws InterruptedException {
        System.out.println("Starting deadlock demo...");
        Thread t1 = new Thread(() -> {
            synchronized (lock1) {
                try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); return; }
                synchronized (lock2) { System.out.println("T1 got both locks"); }
            }
        }, "T1");
        Thread t2 = new Thread(() -> {
            synchronized (lock2) {  // opposite order!
                try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); return; }
                synchronized (lock1) { System.out.println("T2 got both locks"); }
            }
        }, "T2");
        t1.start(); t2.start();
        t1.join(1000);
        t2.join(1000);
        if (t1.isAlive() || t2.isAlive()) {
            System.out.println("Deadlock detected! Threads still blocked after 1s");
            t1.interrupt(); t2.interrupt();
        } else {
            System.out.println("Completed without deadlock (lucky scheduling)");
        }
        System.out.println("Fix: always acquire lock1 BEFORE lock2 in both threads");
    }
}

