import java.util.*;
import java.util.concurrent.atomic.*;
class InventoryManager {
    private Map<String, Integer> stock = new HashMap<>();
    InventoryManager() { stock.put("USB Hub", 10); }

    synchronized boolean purchase(String item, int qty) {
        int current = stock.getOrDefault(item, 0);
        if (current < qty) return false;
        stock.put(item, current - qty);
        return true;
    }
    synchronized int getStock(String item) { return stock.getOrDefault(item, 0); }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        InventoryManager inv = new InventoryManager();
        AtomicInteger success = new AtomicInteger();
        AtomicInteger fail = new AtomicInteger();

        Thread[] threads = new Thread[20];
        for (int i=0; i<20; i++) {
            threads[i] = new Thread(() -> {
                if (inv.purchase("USB Hub", 1)) success.incrementAndGet();
                else fail.incrementAndGet();
            });
        }
        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
        System.out.println("Successful purchases: " + success.get());
        System.out.println("Failed purchases: " + fail.get());
        System.out.println("Final stock: " + inv.getStock("USB Hub"));
    }
}

class Singleton {
    private static volatile Singleton instance;
    private final int id;
    private static int counter = 0;

    private Singleton() { id = ++counter; }

    public static Singleton getInstance() {
        if (instance == null) {               // first check — no lock (fast path)
            synchronized (Singleton.class) {  // lock only if needed
                if (instance == null) {        // second check — with lock
                    instance = new Singleton();
                }
            }
        }
        return instance;
    }
    public int getId() { return id; }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        Thread[] threads = new Thread[5];
        Singleton[] results = new Singleton[5];
        for (int i=0; i<5; i++) {
            final int n = i;
            threads[i] = new Thread(() -> results[n] = Singleton.getInstance());
        }
        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
        boolean allSame = true;
        for (Singleton s : results) if (s != results[0]) allSame = false;
        System.out.println("Singleton instance 1 == Singleton instance 2: " + (results[0] == results[1]));
        System.out.println("Only one instance created: " + allSame);
    }
}

import java.util.*;
class BoundedQueue<T> {
    private final Queue<T> queue = new LinkedList<>();
    private final int capacity;
    BoundedQueue(int cap) { capacity = cap; }

    synchronized void put(T item) throws InterruptedException {
        while (queue.size() >= capacity) wait();  // wait if full
        queue.offer(item);
        notifyAll();  // wake waiting takers
    }

    synchronized T take() throws InterruptedException {
        while (queue.isEmpty()) wait();  // wait if empty
        T item = queue.poll();
        notifyAll();  // wake waiting producers
        return item;
    }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        BoundedQueue<Integer> q = new BoundedQueue<>(5);
        Thread p1 = new Thread(() -> {
            for (int i=1; i<=5; i++) {
                try { q.put(i); System.out.println("Put: " + i); }
                catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        });
        Thread p2 = new Thread(() -> {
            for (int i=6; i<=10; i++) {
                try { q.put(i); System.out.println("Put: " + i); }
                catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        });
        Thread c1 = new Thread(() -> {
            for (int i=0; i<5; i++) {
                try { System.out.println("Took: " + q.take()); }
                catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        });
        Thread c2 = new Thread(() -> {
            for (int i=0; i<5; i++) {
                try { System.out.println("Took: " + q.take()); }
                catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            }
        });
        p1.start(); p2.start(); c1.start(); c2.start();
        p1.join(); p2.join(); c1.join(); c2.join();
        System.out.println("Done");
    }
}

