class OrderProcessor {
    private int orderCount = 0;
    private double totalRevenue = 0.0;

    synchronized void processOrder(double amount) {
        orderCount++;          // protected
        totalRevenue += amount; // protected
    }
    synchronized int getOrderCount()       { return orderCount; }
    synchronized double getTotalRevenue()   { return totalRevenue; }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        OrderProcessor proc = new OrderProcessor();
        Thread[] threads = new Thread[10];
        for (int i=0; i<10; i++) {
            threads[i] = new Thread(() -> {
                for (int j=0; j<5; j++) proc.processOrder(1000.0);
            });
        }
        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
        System.out.println("Order count: " + proc.getOrderCount());
        System.out.printf("Total revenue: ₹%.2f%n", proc.getTotalRevenue());
    }
}

import java.util.*;
class ThreadSafeCache<K, V> {
    private final int maxSize;
    private final Map<K, V> cache;

    ThreadSafeCache(int maxSize) {
        this.maxSize = maxSize;
        this.cache = new LinkedHashMap<>(16, 0.75f, true) {
            protected boolean removeEldestEntry(Map.Entry<K,V> eldest) {
                return size() > maxSize;
            }
        };
    }

    synchronized V get(K key) { return cache.get(key); }

    synchronized void put(K key, V value) { cache.put(key, value); }

    synchronized int size() { return cache.size(); }
}
public class App {
    public static void main(String[] args) throws InterruptedException {
        ThreadSafeCache<Integer, String> cache = new ThreadSafeCache<>(3);
        Thread[] threads = new Thread[10];
        boolean[] noException = {true};

        for (int i=0; i<5; i++) {
            final int n = i;
            threads[i] = new Thread(() -> {
                try {
                    cache.put(n, "value-" + n);
                    cache.get(n % 3);
                } catch (Exception e) { noException[0] = false; }
            });
        }
        for (int i=5; i<10; i++) {
            final int n = i;
            threads[i] = new Thread(() -> {
                try {
                    cache.put(n % 4, "v" + n);
                    cache.get(n % 3);
                } catch (Exception e) { noException[0] = false; }
            });
        }
        for (Thread t : threads) t.start();
        for (Thread t : threads) t.join();
        System.out.println("After concurrent ops, cache size <= 3: " + (cache.size() <= 3));
        System.out.println("Cache operations completed without exception: " + noException[0]);
    }
}
